import org.springframework.beans.factory.annotation.Autowired;  // for autodetection of bean dependencies and injection into fields (Spring beans) via constructor-defined methods or setter(s)-based configuration mechanisms in the application context, as well during component scanning with @ComponentScan annotation if you are using Java Config
import org.springframework.security.core.userdetails.UserDetails;  // to get user details by username and load them into spring security's authentication object (Spring Security)
import org.springframework.security.core.userdetails.UserDetailsService;  
import org.springframework.security.provisioning.UserDetailsManager;    // interface in Spring core that allows users, their roles/authorities to be persisted and managed by the same underlying data source - or different ones if configured differently per user – for example when using LDAP SSO (Single Sign On) with an authentication provider
import org.springframework.stereotype.Service;   // Annotation indicating that a class java_52714_SessionManager_A08 intended as a "Spring bean" to be auto-detected and injected wherever necessary by Spring container or manually provided via setter in Java configuration classes, XML application context files etc., for the purpose of resolving dependencies at runtime
import org.springframework.security.access.AccessDeniedException;  // custom exception when user is trying access a resource which he/she does not have permission to (403)    [Spring Security] - Access Denined if you try accessing forbidden resources or operations where your application doesn't grant them
import org.springframework.security.authentication.*;   // Spring security classes for managing user authentication processes, and provides a way of storing the UserDetailsService to use when authenticating users (also handles providing granted authorities during these auths)  [Spring Security] - Authenticate service if you want something other than username/password based
import org.springframework.security.authentication.dao.*; // Spring security authentication and access-related classes, provides a way to handle user's credentials (which can be used for authorization in role or permission checks) [Spring Security] - DaoAuthenticationProvider  if you want something other than password based
import org.springframework.security.web.authentication.*; // Spring security web authentication related functionalities and util classes, handles request-response processing of an already authenticated user (like adding token to the response etc.) as well [Spring Security] - WebAuthenticationDetailsSource if you want something else than default one
import org.springframework.security.config.*;  // for defining access control rules on what parts or resources are accessible by whom, via Spring security's config classes and annotations (like @EnableWebSecurity) to secure your application with HTTP basic authentication in spring mvc based configuration using http-basic matchers [Spring Security]
import org.springframework.security.crypto.*; // for handling cryptographic operations such as password encryption/decryption, by way of PasswordEncoder and Cipher  (used when storing users' credentials)   [Spring security]. UserDetailsService & AuthenticationProvider should be created in @Autowired Spring Security Config
import org.springframework.security.crypto.bcrypt.*; // BCryptPasswordEncoder is a implementation of Password Encoding Algorithm that uses the BCrypt algorithm (a fast hash function) to safely store passwords  [Spring security] - for encoding user's credentials in spring mvc based configuration
import org.springframework.security.crypto.password.*; // service interface and bean, Spring Security’s way of handling users cryptographic details   using the PasswordEncoder (and Cipher) which has been automatically configured by @Autowired annotation on UserDetailsService & AuthenticationProvider  [Spring security]